/**
 * Team-visibility store — read/write for the team snapshot tables.
 * Pure persistence; every value in = a git/gh fact collected by GitFacade,
 * every value out = exactly what was stored (zero derivation here).
 */
import type { Db } from "./db.js";
export interface RepoRow {
    id: number;
    rootPath: string;
    slug: string | null;
    defaultBranch: string;
}
export interface SyncStateRow {
    lastFetchAt: string | null;
    lastFetchOk: boolean | null;
    ghAvailable: boolean;
    repoFiles: number | null;
    lastSyncedAt: string | null;
}
export interface TeamBranchRow {
    name: string;
    headSha: string;
    lastCommitAt: string;
    lastAuthor: string;
    ahead: number;
    behind: number;
    merged: boolean;
    prNumber: number | null;
    prState: "open" | "merged" | "closed" | null;
    prTitle: string | null;
}
export interface TeamConflictRow {
    branchA: string;
    branchB: string;
    path: string;
    firstDetectedAt: string;
    lastSeenAt: string;
}
export declare function upsertRepo(db: Db, rootPath: string, slug: string | null, defaultBranch: string, now: string): RepoRow;
export declare function getRepoByRoot(db: Db, rootPath: string): RepoRow | null;
export declare function writeSyncState(db: Db, repoId: number, s: SyncStateRow): void;
export declare function readSyncState(db: Db, repoId: number): SyncStateRow | null;
/** Replace the branch set wholesale — the snapshot IS the remote state. */
export declare function replaceTeamBranches(db: Db, repoId: number, branches: TeamBranchRow[]): void;
export declare function readTeamBranches(db: Db, repoId: number): TeamBranchRow[];
export declare function replaceBranchFiles(db: Db, repoId: number, files: Array<{
    branch: string;
    path: string;
    changeKind: string;
}>): void;
export declare function readBranchFiles(db: Db, repoId: number, branch: string): Array<{
    path: string;
    changeKind: string;
}>;
/**
 * Upsert the conflict set for this sync. first_detected_at survives re-syncs
 * (the map's Conflict.detectedAt is "when first detected", not "last seen");
 * pairs that no longer conflict are pruned — resolved is resolved.
 */
export declare function reconcileConflicts(db: Db, repoId: number, seen: Array<{
    branchA: string;
    branchB: string;
    path: string;
}>, now: string): void;
export declare function readConflicts(db: Db, repoId: number): TeamConflictRow[];
